-- =========================================================================
-- SEED DATA FOR E-COMMERCE DATABASE SYSTEM
-- Generated Chronologically and Normalized
-- =========================================================================

BEGIN;

-- Countries
SELECT setval('country_country_id_seq', COALESCE((SELECT MAX(country_id)+1 FROM Country), 1), false);

-- States
SELECT setval('state_state_id_seq', COALESCE((SELECT MAX(state_id)+1 FROM State), 1), false);

-- Cities
SELECT setval('city_city_id_seq', COALESCE((SELECT MAX(city_id)+1 FROM City), 1), false);

-- Users
SELECT setval('users_user_id_seq', COALESCE((SELECT MAX(user_id)+1 FROM Users), 1), false);

-- Addresses
SELECT setval('address_address_id_seq', COALESCE((SELECT MAX(address_id)+1 FROM Address), 1), false);

-- Sellers
SELECT setval('sellers_seller_id_seq', COALESCE((SELECT MAX(seller_id)+1 FROM Sellers), 1), false);

-- Categories
SELECT setval('categories_category_id_seq', COALESCE((SELECT MAX(category_id)+1 FROM Categories), 1), false);

-- Products (Stock quantities are pre-sale values; triggers will decrement them on Order_Items insert)
SELECT setval('products_product_id_seq', COALESCE((SELECT MAX(product_id)+1 FROM Products), 1), false);

-- Tags
SELECT setval('tags_tag_id_seq', COALESCE((SELECT MAX(tag_id)+1 FROM Tags), 1), false);

-- Product Tags

-- Coupons
SELECT setval('coupons_coupon_id_seq', COALESCE((SELECT MAX(coupon_id)+1 FROM Coupons), 1), false);

-- Carts & Wishlists (Session state)
SELECT setval('carts_cart_id_seq', COALESCE((SELECT MAX(cart_id)+1 FROM Carts), 1), false);
SELECT setval('wishlists_wishlist_id_seq', COALESCE((SELECT MAX(wishlist_id)+1 FROM Wishlists), 1), false);

-- Cart Items
SELECT setval('cart_items_cart_item_id_seq', COALESCE((SELECT MAX(cart_item_id)+1 FROM Cart_Items), 1), false);

-- Wishlist Items
SELECT setval('wishlist_items_wishlist_item_id_seq', COALESCE((SELECT MAX(wishlist_item_id)+1 FROM Wishlist_Items), 1), false);

-- Initial Stock Movements (Ledger entries)
SELECT setval('stock_movements_movement_id_seq', COALESCE((SELECT MAX(movement_id)+1 FROM Stock_Movements), 1), false);

-- Orders (Triggers will fire upon subsequent inserts)
SELECT setval('orders_order_id_seq', COALESCE((SELECT MAX(order_id)+1 FROM Orders), 1), false);

-- Shipping Details
SELECT setval('shipping_details_shipping_id_seq', COALESCE((SELECT MAX(shipping_id)+1 FROM Shipping_Details), 1), false);

-- Order Items (This triggers decrement_stock_func)
SELECT setval('order_items_order_item_id_seq', COALESCE((SELECT MAX(order_item_id)+1 FROM Order_Items), 1), false);

-- Payments
SELECT setval('payments_payment_id_seq', COALESCE((SELECT MAX(payment_id)+1 FROM Payments), 1), false);

-- Reviews
SELECT setval('reviews_review_id_seq', COALESCE((SELECT MAX(review_id)+1 FROM Reviews), 1), false);

COMMIT;